UPDATE public.questions SET
  stimulus_text = 'It is often said that the best way to understand a culture is to learn its language. However, this assertion is overly simplistic. While language certainly plays a role in shaping culture, it is only one piece of the puzzle. Other factors, such as history, geography, and social customs, also contribute to the tapestry of a culture. To ignore these other elements is to reduce a complex and multifaceted phenomenon to a single, easily digestible element. Thus, while language is undeniably important, it is not the sole key to unlocking the secrets of a culture.',
  question_text = 'The author uses the phrase "overly simplistic" to suggest that',
  stimulus_type = NULL,
